import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'
import { broadcast } from '@/lib/sse'

/**
 * POST /api/staff/tables/[tableId]/pay
 *
 * Marks all unpaid, non-cancelled orders for a table as PAID.
 * Sets paidAt timestamp on each order. Broadcasts 'order-paid' SSE event.
 *
 * Response: { paid: true, orderIds: number[], paidAt: string }
 *
 * Errors:
 *   400 — invalid tableId
 *   404 — no unpaid orders for this table
 */
export async function POST(
  _request: NextRequest,
  { params }: { params: Promise<{ tableId: string }> }
) {
  const { tableId: tableIdStr } = await params
  const tableId = parseInt(tableIdStr, 10)

  if (isNaN(tableId)) {
    return NextResponse.json(
      { error: 'ID bàn không hợp lệ.' },
      { status: 400 }
    )
  }

  console.log(`[POST /api/staff/tables/${tableId}/pay] Processing payment`)

  // ─── Find unpaid orders ───────────────────────────────────────────
  const unpaidOrders = await prisma.order.findMany({
    where: {
      tableId,
      status: { notIn: ['PAID', 'CANCELLED'] },
    },
    select: { id: true },
  })

  if (unpaidOrders.length === 0) {
    console.log(
      `[POST /api/staff/tables/${tableId}/pay] No unpaid orders found`
    )
    return NextResponse.json(
      { error: 'Bàn này không có đơn chưa thanh toán.' },
      { status: 404 }
    )
  }

  const orderIds = unpaidOrders.map((o) => o.id)
  const paidAt = new Date()

  // ─── Mark all as PAID in a single transaction ─────────────────────
  try {
    await prisma.$transaction(
      orderIds.map((id) =>
        prisma.order.update({
          where: { id },
          data: { status: 'PAID', paidAt },
        })
      )
    )

    console.log(
      `[POST /api/staff/tables/${tableId}/pay] Marked ${orderIds.length} orders as PAID: [${orderIds.join(', ')}], paidAt=${paidAt.toISOString()}`
    )

    // ─── Broadcast SSE event ──────────────────────────────────────────
    broadcast('order-paid', { tableId, orderIds, paidAt: paidAt.toISOString() })

    return NextResponse.json({
      paid: true,
      orderIds,
      paidAt: paidAt.toISOString(),
    })
  } catch (error) {
    console.error(
      `[POST /api/staff/tables/${tableId}/pay] Transaction failed:`,
      error
    )
    return NextResponse.json(
      { error: 'Không thể xử lý thanh toán. Vui lòng thử lại.' },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/staff/tables/[tableId]/bill
 *
 * Aggregates all unpaid, non-cancelled orders for a table into a single bill.
 * Returns table info, individual orders, a flat item list, and the aggregated total.
 *
 * Response shape:
 *   { table: { id, number, name }, orders: [...], items: [...], total: number }
 *
 * Errors:
 *   400 — invalid tableId
 *   404 — no unpaid orders for this table
 */
export async function GET(
  _request: NextRequest,
  { params }: { params: Promise<{ tableId: string }> }
) {
  const { tableId: tableIdStr } = await params
  const tableId = parseInt(tableIdStr, 10)

  if (isNaN(tableId)) {
    return NextResponse.json(
      { error: 'ID bàn không hợp lệ.' },
      { status: 400 }
    )
  }

  console.log(`[GET /api/staff/tables/${tableId}/bill] Fetching bill`)

  // ─── Query unpaid, non-cancelled orders ───────────────────────────
  const orders = await prisma.order.findMany({
    where: {
      tableId,
      status: { notIn: ['PAID', 'CANCELLED'] },
    },
    include: {
      table: true,
      items: {
        include: {
          menuItem: {
            select: { id: true, name: true, category: true, price: true },
          },
        },
      },
    },
    orderBy: { createdAt: 'asc' },
  })

  if (orders.length === 0) {
    console.log(
      `[GET /api/staff/tables/${tableId}/bill] No unpaid orders found`
    )
    return NextResponse.json(
      { error: 'Bàn này không có đơn chưa thanh toán.' },
      { status: 404 }
    )
  }

  // ─── Build flat item list and compute total ───────────────────────
  const table = { id: orders[0].table.id, number: orders[0].table.number, name: orders[0].table.name }

  const items = orders.flatMap((order) =>
    order.items.map((item) => ({
      id: item.id,
      orderId: order.id,
      menuItemId: item.menuItem.id,
      name: item.menuItem.name,
      category: item.menuItem.category,
      price: item.menuItem.price,
      quantity: item.quantity,
      status: item.status,
      notes: item.notes,
    }))
  )

  // Total excludes CANCELLED items
  const total = items.reduce((sum, item) => {
    if (item.status === 'CANCELLED') return sum
    return sum + item.price * item.quantity
  }, 0)

  console.log(
    `[GET /api/staff/tables/${tableId}/bill] Found ${orders.length} orders, ${items.length} items, total=${total}`
  )

  return NextResponse.json({ table, orders, items, total })
}

import { PrismaClient } from '../../generated/prisma/client'
import { PrismaBetterSqlite3 } from '@prisma/adapter-better-sqlite3'

const globalForPrisma = globalThis as unknown as { prisma: PrismaClient }

export const prisma =
  globalForPrisma.prisma ??
  new PrismaClient({
    adapter: new PrismaBetterSqlite3({ url: 'file:prisma/dev.db' }),
  })

if (process.env.NODE_ENV !== 'production') globalForPrisma.prisma = prisma

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/prisma'

/**
 * GET /api/admin/menu
 *
 * Returns ALL menu items (including hidden), ordered by sortOrder.
 * Admin middleware handles authentication.
 */
export async function GET() {
  try {
    const items = await prisma.menuItem.findMany({
      orderBy: { sortOrder: 'asc' },
    })

    console.log(`[GET /api/admin/menu] Returning ${items.length} menu items (including hidden)`)

    return NextResponse.json({ items })
  } catch (error) {
    console.error('[GET /api/admin/menu] Failed to fetch menu items:', error)
    return NextResponse.json(
      { error: 'Không thể tải danh sách món. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

/**
 * POST /api/admin/menu
 *
 * Creates a new menu item.
 * Required: name (string), price (int > 0), category (DRINK | FOOD).
 * Optional: description (string), sortOrder (int), available (boolean).
 */
export async function POST(request: NextRequest) {
  let body: Record<string, unknown>
  try {
    body = await request.json()
  } catch {
    return NextResponse.json(
      { error: 'Dữ liệu không hợp lệ.' },
      { status: 400 },
    )
  }

  const { name, price, category, description, sortOrder, available } = body

  // --- Validate required fields ---
  if (!name || typeof name !== 'string' || name.trim().length === 0) {
    return NextResponse.json(
      { error: 'Tên món không được để trống' },
      { status: 400 },
    )
  }

  if (typeof price !== 'number' || !Number.isInteger(price) || price <= 0) {
    return NextResponse.json(
      { error: 'Giá phải lớn hơn 0' },
      { status: 400 },
    )
  }

  if (category !== 'DRINK' && category !== 'FOOD') {
    return NextResponse.json(
      { error: 'Danh mục phải là DRINK hoặc FOOD' },
      { status: 400 },
    )
  }

  try {
    const item = await prisma.menuItem.create({
      data: {
        name: name.trim(),
        price,
        category,
        description: typeof description === 'string' ? description.trim() : null,
        sortOrder: typeof sortOrder === 'number' && Number.isInteger(sortOrder) ? sortOrder : 0,
        available: typeof available === 'boolean' ? available : true,
      },
    })

    console.log(`[POST /api/admin/menu] Created menu item #${item.id}: ${item.name}`)

    return NextResponse.json({ item }, { status: 201 })
  } catch (error) {
    console.error('[POST /api/admin/menu] Failed to create menu item:', error)
    return NextResponse.json(
      { error: 'Không thể tạo món mới. Vui lòng thử lại.' },
      { status: 500 },
    )
  }
}

'use client'

import { useEffect, useState } from 'react'
import { createPortal } from 'react-dom'

// ─── Types ──────────────────────────────────────────────────────────

export interface ToastData {
  id: string
  message: string
  variant: 'success' | 'error'
}

interface ToastProps {
  toast: ToastData
  onDismiss: (id: string) => void
}

// ─── Single Toast ───────────────────────────────────────────────────

function ToastItem({ toast, onDismiss }: ToastProps) {
  const [visible, setVisible] = useState(false)

  useEffect(() => {
    // Trigger slide-in
    const frameId = requestAnimationFrame(() => setVisible(true))
    return () => cancelAnimationFrame(frameId)
  }, [])

  useEffect(() => {
    const timer = setTimeout(() => {
      setVisible(false)
      // Wait for exit animation before removing
      setTimeout(() => onDismiss(toast.id), 200)
    }, 3000)
    return () => clearTimeout(timer)
  }, [toast.id, onDismiss])

  const bg =
    toast.variant === 'success'
      ? 'bg-emerald-600'
      : 'bg-red-600'

  return (
    <div
      role="status"
      aria-live="polite"
      className={`
        ${bg} text-white text-sm font-medium
        px-4 py-3 rounded-xl shadow-lg
        transition-all duration-200 ease-out
        ${visible ? 'translate-y-0 opacity-100' : 'translate-y-3 opacity-0'}
      `}
    >
      <span className="mr-2" aria-hidden="true">
        {toast.variant === 'success' ? '✓' : '✕'}
      </span>
      {toast.message}
    </div>
  )
}

// ─── Toast Container (Portal) ───────────────────────────────────────

export default function ToastContainer({ toasts, onDismiss }: {
  toasts: ToastData[]
  onDismiss: (id: string) => void
}) {
  const [mounted, setMounted] = useState(false)

  useEffect(() => {
    setMounted(true)
  }, [])

  if (!mounted || toasts.length === 0) return null

  return createPortal(
    <div
      className="fixed bottom-24 left-1/2 -translate-x-1/2 z-[60] flex flex-col-reverse gap-2 w-[min(90vw,360px)] pointer-events-none"
      aria-label="Thông báo"
    >
      {toasts.map((t) => (
        <div key={t.id} className="pointer-events-auto">
          <ToastItem toast={t} onDismiss={onDismiss} />
        </div>
      ))}
    </div>,
    document.body,
  )
}
